#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e5+5;
const ULL Base = 998244353;
ULL n,a[N],P[N],s[N],t[N],ans;
unordered_set<ULL> st;vector<int> g;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read();for(int i=1;i<=n;i++)a[i]=read();
    P[0]=1;for(int i=1;i<=n;i++)P[i]=P[i-1]*Base;
    for(int i=1;i<=n;i++)s[i]=s[i-1]*Base+a[i];
    for(int i=n;i>=1;i--)t[i]=t[i+1]*Base+a[i];
    for(int k=1;n/k>=ans;k++){
        ULL sum=0;st.clear();
        for(int i=k;i<=n;i+=k){
            ULL h1=s[i]-s[i-k]*P[k];
            ULL h2=t[i-k+1]-t[i+1]*P[k];
            if(!st.count(h1))sum++;
            st.insert(h1),st.insert(h2);
        }
        if(sum>ans)ans=sum,g.clear();
        if(sum==ans)g.pb(k);
    }
    cout<<ans<<" "<<g.size()<<"\n";
    for(int u:g)cout<<u<<" ";cout<<"\n";
    return 0;
}
